    # ── JOINs ──────────────────────────────────────────
    {"topic":"joins","diff":2,"title":"Order With Customer Name",
     "description":"Return o.id, c.name, o.amount joining orders to customers, ordered by o.id.",
     "sample_data":"CREATE TABLE customers(id INT,name TEXT);\nINSERT INTO customers VALUES(1,'Alice'),(2,'Bob'),(3,'Carol');\nCREATE TABLE orders(id INT,customer_id INT,amount REAL);\nINSERT INTO orders VALUES(10,1,100),(11,1,50),(12,2,200);",
     "expected_output":"10|Alice|100.0\n11|Alice|50.0\n12|Bob|200.0",
     "solution":"SELECT o.id, c.name, o.amount FROM orders o JOIN customers c ON c.id = o.customer_id ORDER BY o.id;",
     "tags":["sql:joins"],"hints":["INNER JOIN.","ON c.id = o.customer_id.","JOIN customers c ON c.id = o.customer_id"]},
    {"topic":"joins","diff":2,"title":"Customers Without Orders",
     "description":"Return name of customers with zero orders.",
     "sample_data":"CREATE TABLE customers(id INT,name TEXT);\nINSERT INTO customers VALUES(1,'Alice'),(2,'Bob'),(3,'Carol');\nCREATE TABLE orders(id INT,customer_id INT,amount REAL);\nINSERT INTO orders VALUES(10,1,100),(11,1,50),(12,2,200);",
     "expected_output":"Carol",
     "solution":"SELECT c.name FROM customers c LEFT JOIN orders o ON o.customer_id = c.id WHERE o.id IS NULL ORDER BY c.name;",
     "tags":["sql:joins"],"hints":["LEFT JOIN.","Unmatched rows become NULL.","WHERE o.id IS NULL"]},
    {"topic":"joins","diff":3,"title":"Total Spend Per Customer",
     "description":"Return name, total_spend for every customer (NULL becomes 0), ordered by name.",
     "sample_data":"CREATE TABLE customers(id INT,name TEXT);\nINSERT INTO customers VALUES(1,'Alice'),(2,'Bob'),(3,'Carol');\nCREATE TABLE orders(id INT,customer_id INT,amount REAL);\nINSERT INTO orders VALUES(10,1,100),(11,1,50),(12,2,200);",
     "expected_output":"Alice|150.0\nBob|200.0\nCarol|0",
     "solution":"SELECT c.name, COALESCE(SUM(o.amount),0) AS total_spend FROM customers c LEFT JOIN orders o ON o.customer_id=c.id GROUP BY c.id, c.name ORDER BY c.name;",
     "tags":["sql:joins","sql:aggregation"],"hints":["LEFT JOIN keeps all customers.","COALESCE for NULL totals.","GROUP BY c.id, c.name"]},
    {"topic":"joins","diff":3,"title":"Employees And Their Managers",
     "description":"Return employee_name, manager_name for every employee. If no manager, show NULL.",
     "sample_data":"CREATE TABLE emp(id INT,name TEXT,manager_id INT);\nINSERT INTO emp VALUES(1,'Alice',NULL),(2,'Bob',1),(3,'Carol',1),(4,'Dan',2);",
     "expected_output":"Alice|None\nBob|Alice\nCarol|Alice\nDan|Bob",
     "solution":"SELECT e.name AS employee_name, m.name AS manager_name FROM emp e LEFT JOIN emp m ON m.id = e.manager_id ORDER BY e.id;",
     "tags":["sql:joins","sql:advanced_joins"],"hints":["Self-join: alias the same table twice.","LEFT JOIN for nullable manager.","LEFT JOIN emp m ON m.id = e.manager_id"]},
    {"topic":"joins","diff":3,"title":"Three Table Join",
     "description":"Return customer_name, product_name, qty joining orders to customers and products. Sort by customer_name, product_name.",
     "sample_data":"CREATE TABLE customers(id INT,name TEXT);\nINSERT INTO customers VALUES(1,'Alice'),(2,'Bob');\nCREATE TABLE products(id INT,name TEXT);\nINSERT INTO products VALUES(10,'Pen'),(11,'Mug');\nCREATE TABLE orders(id INT,customer_id INT,product_id INT,qty INT);\nINSERT INTO orders VALUES(1,1,10,2),(2,1,11,1),(3,2,10,3);",
     "expected_output":"Alice|Mug|1\nAlice|Pen|2\nBob|Pen|3",
     "solution":"SELECT c.name AS customer_name, p.name AS product_name, o.qty FROM orders o JOIN customers c ON c.id=o.customer_id JOIN products p ON p.id=o.product_id ORDER BY c.name, p.name;",
     "tags":["sql:joins"],"hints":["Chain two JOINs.","One JOIN per FK.","JOIN customers c ON ... JOIN products p ON ..."]},
    {"topic":"joins","diff":3,"title":"Products Never Sold",
     "description":"Return name of products with no rows in sales.",
     "sample_data":"CREATE TABLE products(id INT,name TEXT);\nINSERT INTO products VALUES(1,'A'),(2,'B'),(3,'C');\nCREATE TABLE sales(id INT,product_id INT);\nINSERT INTO sales VALUES(1,1),(2,1),(3,3);",
     "expected_output":"B",
     "solution":"SELECT p.name FROM products p LEFT JOIN sales s ON s.product_id=p.id WHERE s.id IS NULL ORDER BY p.name;",
     "tags":["sql:joins"],"hints":["LEFT JOIN + IS NULL.","Anti-join pattern.","WHERE s.id IS NULL"]},
    {"topic":"joins","diff":3,"title":"Cartesian Pairing",
     "description":"Given sizes(s) and colors(c), return every (s,c) pair ordered by size then color.",
     "sample_data":"CREATE TABLE sizes(s TEXT);\nINSERT INTO sizes VALUES('S'),('M'),('L');\nCREATE TABLE colors(c TEXT);\nINSERT INTO colors VALUES('red'),('blue');",
     "expected_output":"L|blue\nL|red\nM|blue\nM|red\nS|blue\nS|red",
     "solution":"SELECT s.s AS size, c.c AS color FROM sizes s CROSS JOIN colors c ORDER BY s.s, c.c;",
     "tags":["sql:joins","sql:advanced_joins"],"hints":["CROSS JOIN = every combination.","No ON clause.","CROSS JOIN"]},
    {"topic":"joins","diff":3,"title":"Customers Who Bought Product 10",
     "description":"Return distinct name of customers who ever bought product_id=10.",
     "sample_data":"CREATE TABLE customers(id INT,name TEXT);\nINSERT INTO customers VALUES(1,'A'),(2,'B'),(3,'C');\nCREATE TABLE orders(id INT,customer_id INT,product_id INT);\nINSERT INTO orders VALUES(1,1,10),(2,2,11),(3,3,10),(4,1,10);",
     "expected_output":"A\nC",
     "solution":"SELECT DISTINCT c.name FROM customers c WHERE EXISTS(SELECT 1 FROM orders o WHERE o.customer_id=c.id AND o.product_id=10) ORDER BY c.name;",
     "tags":["sql:joins","sql:subquery"],"hints":["EXISTS or IN subquery.","DISTINCT to dedupe.","WHERE EXISTS (SELECT 1 FROM orders ...)"]},

