    {"topic":"window_functions","diff":3,"title":"Share Of Department Salary",
     "description":"Return name, department, share where share = ROUND(salary*1.0 / SUM(salary) OVER (PARTITION BY department), 2).",
     "sample_data":"CREATE TABLE emp(id INT,name TEXT,department TEXT,salary INT);\nINSERT INTO emp VALUES(1,'A','Eng',100),(2,'B','Eng',120),(3,'C','Eng',90),(4,'D','Sales',80),(5,'E','Sales',95);",
     "expected_output":"A|Eng|0.32\nB|Eng|0.39\nC|Eng|0.29\nD|Sales|0.46\nE|Sales|0.54",
     "solution":"SELECT name, department, ROUND(salary*1.0 / SUM(salary) OVER (PARTITION BY department), 2) AS share FROM emp ORDER BY department, name;",
     "tags":["sql:window_functions"],"hints":["Ratio with windowed SUM.","PARTITION BY department.","SUM(salary) OVER (PARTITION BY department)"]},
    {"topic":"window_functions","diff":4,"title":"Salary Quartiles NTILE",
     "description":"Return name, salary, q where q = NTILE(4) OVER (ORDER BY salary).",
     "sample_data":"CREATE TABLE emp(id INT,name TEXT,salary INT);\nINSERT INTO emp VALUES(1,'A',60),(2,'B',70),(3,'C',80),(4,'D',90),(5,'E',100),(6,'F',110),(7,'G',120),(8,'H',130);",
     "expected_output":"A|60|1\nB|70|1\nC|80|2\nD|90|2\nE|100|3\nF|110|3\nG|120|4\nH|130|4",
     "solution":"SELECT name, salary, NTILE(4) OVER (ORDER BY salary) AS q FROM emp ORDER BY salary;",
     "tags":["sql:window_functions"],"hints":["NTILE(n) splits rows into n buckets.","ORDER BY salary asc.","NTILE(4) OVER (ORDER BY salary)"]},
    {"topic":"window_functions","diff":3,"title":"First Login Per User",
     "description":"For each row return user_id, ts, first_ts where first_ts is FIRST_VALUE(ts) OVER (PARTITION BY user_id ORDER BY ts).",
     "sample_data":"CREATE TABLE logins(user_id INT,ts INT);\nINSERT INTO logins VALUES(1,100),(1,200),(2,150),(2,180),(1,300);",
     "expected_output":"1|100|100\n1|200|100\n1|300|100\n2|150|150\n2|180|150",
     "solution":"SELECT user_id, ts, FIRST_VALUE(ts) OVER (PARTITION BY user_id ORDER BY ts) AS first_ts FROM logins ORDER BY user_id, ts;",
     "tags":["sql:window_functions"],"hints":["FIRST_VALUE.","PARTITION BY user_id.","FIRST_VALUE(ts) OVER (PARTITION BY user_id ORDER BY ts)"]},

