    # ── CASE WHEN ──────────────────────────────────────
    {"topic":"case_when","diff":2,"title":"Salary Buckets",
     "description":"Return name, bucket where bucket = low if salary<80, mid if <120, else high. Order by name.",
     "sample_data":"CREATE TABLE emp(id INT,name TEXT,salary INT);\nINSERT INTO emp VALUES(1,'A',60),(2,'B',100),(3,'C',150),(4,'D',80);",
     "expected_output":"A|low\nB|mid\nC|high\nD|mid",
     "solution":"SELECT name, CASE WHEN salary < 80 THEN 'low' WHEN salary < 120 THEN 'mid' ELSE 'high' END AS bucket FROM emp ORDER BY name;",
     "tags":["sql:case_when"],"hints":["CASE WHEN ... THEN ... ELSE ... END.","Conditions checked in order.","CASE WHEN salary<80 THEN 'low' ..."]},
    {"topic":"case_when","diff":2,"title":"Email Or Fallback",
     "description":"Return id, email_or_unknown where missing emails show unknown.",
     "sample_data":"CREATE TABLE u(id INT,email TEXT); INSERT INTO u VALUES(1,'a@x.com'),(2,NULL),(3,'c@x.com');",
     "expected_output":"1|a@x.com\n2|unknown\n3|c@x.com",
     "solution":"SELECT id, COALESCE(email,'unknown') AS email_or_unknown FROM u ORDER BY id;",
     "tags":["sql:case_when","sql:null_semantics"],"hints":["COALESCE is cleaner than CASE here.","Same as CASE WHEN email IS NULL.","COALESCE(email,'unknown')"]},
    {"topic":"case_when","diff":3,"title":"Conditional Counting",
     "description":"Return paid_count and cancelled_count as a single row using SUM(CASE...).",
     "sample_data":"CREATE TABLE orders(id INT,status TEXT);\nINSERT INTO orders VALUES(1,'paid'),(2,'cancelled'),(3,'paid'),(4,'pending'),(5,'paid');",
     "expected_output":"3|1",
     "solution":"SELECT SUM(CASE WHEN status='paid' THEN 1 ELSE 0 END) AS paid_count, SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END) AS cancelled_count FROM orders;",
     "tags":["sql:case_when","sql:aggregation"],"hints":["Pivot-style aggregation.","SUM(CASE...).","SUM(CASE WHEN status='paid' THEN 1 ELSE 0 END)"]},
    {"topic":"case_when","diff":3,"title":"Pivot Status By Day",
     "description":"For each day, return day, paid, cancelled counts sorted by day.",
     "sample_data":"CREATE TABLE orders(id INT,day INT,status TEXT);\nINSERT INTO orders VALUES(1,1,'paid'),(2,1,'cancelled'),(3,2,'paid'),(4,2,'paid'),(5,3,'cancelled');",
     "expected_output":"1|1|1\n2|2|0\n3|0|1",
     "solution":"SELECT day, SUM(CASE WHEN status='paid' THEN 1 ELSE 0 END) AS paid, SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END) AS cancelled FROM orders GROUP BY day ORDER BY day;",
     "tags":["sql:case_when","sql:group_by"],"hints":["GROUP BY day.","CASE inside SUM.","SUM(CASE WHEN status='paid' THEN 1 ELSE 0 END)"]},

